import{c as s,Q as n,j as e,m as t}from"./chunks/framework.iD28w_5a.js";const h=JSON.parse('{"title":"时间片过长","description":"","frontmatter":{"title":"时间片过长"},"headers":[],"relativePath":"notes/020/001_time_slice_too_long.md","filePath":"notes/020/001_time_slice_too_long.md","lastUpdated":1779686691000}'),l={name:"notes/020/001_time_slice_too_long.md"};function i(r,a,o,p,c,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="_020-·-时间片过长导致抢占从未触发" tabindex="-1">020 · 时间片过长导致抢占从未触发 <a class="header-anchor" href="#_020-·-时间片过长导致抢占从未触发" aria-label="Permalink to &quot;020 · 时间片过长导致抢占从未触发&quot;">​</a></h1><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p>3 个线程各跑 5 次迭代，完全顺序执行，没有任何交错：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[A] thread_a iteration 0</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[A] thread_a iteration 4</span></span>
<span class="line"><span>[B] thread_b iteration 0</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[B] thread_b iteration 4</span></span>
<span class="line"><span>[C] thread_c iteration 0</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h2><p>PIT 配置为 100Hz（每 tick 10ms），<code>DEFAULT_TIME_SLICE = 10</code>，即 <strong>100ms 才触发一次抢占</strong>。</p><p>忙循环 <code>for (volatile int j = 0; j &lt; 1000000; j++) {}</code> 在 QEMU TCG 模式下执行极快，单次迭代 &lt; 5ms。每个线程 5 次迭代总耗时 &lt; 50ms，远小于 100ms 时间片——线程在自己的时间片内就跑完了。</p><h2 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h2><ol><li><strong>缩短时间片</strong>：<code>DEFAULT_TIME_SLICE</code> 从 10 改为 2（20ms）。</li><li><strong>增大忙循环</strong>：迭代次数从 1M 提升到 20M，确保每个线程跨越多个时间片。</li></ol><h2 id="教训" tabindex="-1">教训 <a class="header-anchor" href="#教训" aria-label="Permalink to &quot;教训&quot;">​</a></h2><p>在虚拟化环境中，简单的 CPU 密集循环比预期快得多。测试抢占调度时，要确保工作负载足够大，或者时间片足够小，让定时器中断有机会介入。</p>`,11)])])}const m=s(l,[["render",i]]);export{h as __pageData,m as default};
